        Dispatchers.setMain(mainDispatcher)
        try {
            val rawUri = "aetherlink://pair?v=1&n=nonce-1&c=123456" +
                "&rid=runtime-1&rn=AetherLink%20Runtime&rf=runtime-fingerprint" +
                "&rk=runtime-public-key&rt=route-1" +
