            fixture.viewModel.searchRuntimeDocuments("source anchor lexical snippet")
            advanceUntilIdle()

            val invalidSnippetRequest = fixture.channel.sentEnvelopes.last { it.type == MessageType.RetrievalQuery }
            fixture.channel.enqueue(
