                fixture.localStore.data.sessions.single { it.id == "runtime-session" }
                    .messages.last().sourceAttributions.single().documentName,
            )
            assertEquals(
                historyAssistantMessageId,
                fixture.localStore.data.sessions.single { it.id == "runtime-session" }
                    .messages.last().assistantMessageId,
