    @Test
    fun runtimeAuthenticationErrorTransitionsToPairingRequiredState() {
        val state = RuntimeUiState(
            isConnected = true,
            isConnecting = true,
            isStreaming = true,
            isLoadingModels = true,
            installingModelId = "ollama:llama3",
            activeRequestId = "hello-request",
