                    pendingAttachments = listOf(
                        textAttachment().copy(id = "existing-1", name = "existing-1.txt"),
                        textAttachment().copy(id = "existing-2", name = "existing-2.txt"),
                        textAttachment().copy(id = "existing-3", name = "existing-3.txt"),
