    fun persistedRuntimeDataStoresPendingP2pRendezvousRouteUntilShorterRecordExpiry() {
        val now = 1_000L
        val p2pExpiresAt = now + 90_000L
        val maxSizedP2pEncryptedBody = maxSizedOpaqueP2pEncryptedBody()
        val payload = runtimePairingPayload(
