    @Test
    fun clientCapabilitiesDoNotAdvertiseFutureWorkspaceRagSourceProtocols() {
        val reservedFutureCapabilities = listOf(
            "embeddings.create",
            "index.build",
            "research.brief.create",
            "citation.sources.list",
            "source_anchor.resolve",
            "source_control.status",
            "projects.sessions.list",
            "automation.runs.create",
            "tool.call",
            "tool.result",
            "tool.run",
            "skills.run",
            "mcp.tool.call",
            "web_search.query",
            "python.run",
            "python.exec",
            "permission.request",
            "approval.prompt",
            "audit.events.list",
            "file.read",
            "file.write",
            "file.index",
            "terminal.exec",
            "terminal.kill",
            "network.request",
            "network.open",
            "backend.call",
            "backend.configure",
            "memory.search",
            "route.candidates.exchange",
            "route.diagnostics.report",
            "route.allocation.status",
            "route.failure.report",
        )

        val defaultCapabilities = runtimeClientCapabilities(authenticatedRouteRefreshEnabled = false)
        val diagnosticCapabilities = runtimeClientCapabilities(authenticatedRouteRefreshEnabled = true)

        reservedFutureCapabilities.forEach { capability ->
            assertFalse("Default hello must not advertise $capability", defaultCapabilities.contains(capability))
            assertFalse("Diagnostic hello must not advertise $capability", diagnosticCapabilities.contains(capability))
        }
        assertTrue(defaultCapabilities.contains(MessageType.IndexDocumentsList))
        assertTrue(defaultCapabilities.contains(MessageType.RetrievalQuery))
        assertTrue(diagnosticCapabilities.contains(MessageType.RouteRefresh))
    }

    private fun trustedSourceSearchResultJson(anchorId: String): JsonObject {
        return json.parseToJsonElement(
            """
                {
                  "results": [{
                    "document": {
                      "id": "doc-trusted-source",
                      "display_name": "Trusted Source.md",
                      "mime_type": "text/markdown",
                      "content_fingerprint": "0011223344556677",
                      "extracted_character_count": 1024,
                      "chunk_count": 4,
                      "quality": "chunked"
                    },
                    "source_anchor_id": "$anchorId",
                    "chunk_index": 2,
                    "start_character_offset": 200,
                    "end_character_offset": 320,
                    "rank": 1,
                    "match_kind": "lexical",
                    "matched_terms": ["trusted", "source"],
                    "snippet": "A safe search result."
                  }]
                }
            """.trimIndent(),
        ).jsonObject
    }

    private fun citationResolveResultJson(
        anchorId: String,
        citationId: String,
        reviewId: String,
        confirmationToken: String,
    ): JsonObject {
        return json.parseToJsonElement(
            """
                {
                  "citation": {
                    "schema_version": 1,
                    "citation_id": "$citationId",
                    "source_anchor_id": "$anchorId",
                    "document": {
                      "id": "doc-trusted-source",
                      "display_name": "Trusted Source.md",
                      "mime_type": "text/markdown",
                      "content_fingerprint": "0011223344556677",
                      "extracted_character_count": 1024,
                      "chunk_count": 4,
                      "quality": "chunked"
                    },
                    "chunk_summary": {
                      "chunk_index": 2,
                      "start_character_offset": 200,
                      "end_character_offset": 320,
                      "character_count": 120
                    }
                  },
                  "review": {
                    "review_id": "$reviewId",
                    "confirmation_token": "$confirmationToken",
                    "disclosure_version": "runtime-trusted-source-v1",
                    "usage_scope": "chat_context",
                    "expires_at": "2026-07-12T12:30:00Z"
                  }
                }
            """.trimIndent(),
        ).jsonObject
    }

