                    payload = RuntimeHealthPayload(status = "ok"),
                    requestId = replacementRuntimeHealthRequest.requestId,
                ),
            )
            advanceUntilIdle()
            val currentModelsRequest = replacementChannel.sentEnvelopes.last {
                it.type == MessageType.ModelsList
