    @OptIn(ExperimentalCoroutinesApi::class)
    private suspend fun TestScope.createAuthenticatedRuntimeClientFixture(
        models: List<RuntimeModel>,
        modelPayloads: List<ModelInfoPayload> = models.map { it.toModelInfoPayload() },
        selectedModelId: String = models.first().id,
        selectedEmbeddingModelId: String? = null,
        attachmentReader: RuntimeAttachmentReader? = null,
        attachmentIoDispatcher: CoroutineDispatcher = Dispatchers.Main,
        attachmentIoTimeoutMillis: Long = DEFAULT_ATTACHMENT_IO_TIMEOUT_MILLIS,
        attachmentBudgets: RuntimeAttachmentBudgets = RuntimeAttachmentBudgets(),
        redactRuntimeOwnedLocalDataOnSave: Boolean = false,
        initialData: PersistedRuntimeData? = null,
        replacementChannel: ScriptedRuntimeProtocolChannel? = null,
        leaveResearchNotebooksPending: Boolean = false,
        runtimeCapabilities: List<String> = listOf(MEMORY_SUMMARY_DRAFT_APPROVAL_METHOD_CAPABILITY),
        memoryMutationRequestTimeoutMillis: Long? = null,
        memorySummaryControlRequestTimeoutMillis: Long? = null,
        memorySummaryGenerationRequestTimeoutMillis: Long? = null,
        volatileStatePersistenceCoalesceMillis: Long = 0L,
    ): RuntimeClientFixture {
        val leaveScheduledTimeoutsPending =
            leaveResearchNotebooksPending ||
                memorySummaryControlRequestTimeoutMillis != null ||
                memorySummaryGenerationRequestTimeoutMillis != null
        val channel = ScriptedRuntimeProtocolChannel()
        var relayConnectionCount = 0
        val localStore = FakeRuntimeLocalDataStore(
            initialData = initialData ?: PersistedRuntimeData(
                selectedModelId = selectedModelId,
                selectedEmbeddingModelId = selectedEmbeddingModelId,
                trustedRuntimeAutoReconnectEnabled = false,
            ),
            redactRuntimeOwnedLocalDataOnSave = redactRuntimeOwnedLocalDataOnSave,
        )
        val trustedStore = FakeEmittingTrustedRuntimeStore(trustedRuntimeForViewModelTests())
        val viewModel = RuntimeClientViewModel(
            application = Application(),
            dependencies = RuntimeClientViewModelDependencies(
                json = json,
                transportClient = RuntimeTransportClient(),
                transportConnector = RuntimeTransportConnector { _, _, _ ->
                    error("Direct TCP should not be used by attachment send-path tests")
                },
                relayConnector = RuntimeRelayConnector { _, _ ->
                    if (relayConnectionCount++ == 0) channel else replacementChannel ?: channel
                },
                discovery = EmptyRuntimeDiscoverySource,
                trustedRuntimeStore = trustedStore,
                deviceIdentityProvider = FakeDeviceIdentityProvider(testDeviceIdentity()),
                localDataStore = localStore,
                lifecycleCallbacksRegistrar = NoopRuntimeLifecycleCallbacksRegistrar,
                attachmentReader = attachmentReader,
                attachmentIoDispatcher = attachmentIoDispatcher,
                attachmentIoTimeoutMillis = attachmentIoTimeoutMillis,
                attachmentBudgets = attachmentBudgets,
                attachmentPromptHeaderProvider = ::testAttachmentOnlyPromptHeader,
                memoryMutationRequestTimeoutMillis = memoryMutationRequestTimeoutMillis,
                memorySummaryControlRequestTimeoutMillis =
                    memorySummaryControlRequestTimeoutMillis,
                memorySummaryGenerationRequestTimeoutMillis =
                    memorySummaryGenerationRequestTimeoutMillis,
                volatileStatePersistenceCoalesceMillis =
                    volatileStatePersistenceCoalesceMillis,
                currentTimeMillis = { 1_000L },
            ),
        )
        advanceUntilIdle()

        viewModel.connectToTrustedRuntime()
        advanceUntilIdle()
        completeRuntimeAuthentication(
            viewModel = viewModel,
            channel = channel,
            runtimeCapabilities = runtimeCapabilities,
        )
        if (!leaveResearchNotebooksPending) {
            val researchNotebooksRequest = channel.sentEnvelopes.lastOrNull {
                it.type == MessageType.ResearchNotebooksList
            }
            if (researchNotebooksRequest != null) {
                channel.enqueue(
                    envelope(
                        type = MessageType.ResearchNotebooksList,
                        requestId = researchNotebooksRequest.requestId,
                        serializer = ResearchNotebooksListResultPayload.serializer(),
                        payload = ResearchNotebooksListResultPayload(
                            notebooks = emptyList(),
                            snapshotCount = 0,
                        ),
                    ),
                )
            }
        }
        if (leaveScheduledTimeoutsPending) runCurrent() else advanceUntilIdle()
        val runtimeHealthRequest = channel.sentEnvelopes.last {
            it.type == MessageType.RuntimeHealth
        }
        assertTrue(runtimeHealthRequest.requestId.startsWith("runtime-health-"))
        channel.enqueue(
            envelope(
                type = MessageType.RuntimeHealth,
                serializer = RuntimeHealthPayload.serializer(),
                payload = RuntimeHealthPayload(status = "ok"),
                requestId = runtimeHealthRequest.requestId,
            ),
        )
        if (leaveScheduledTimeoutsPending) runCurrent() else advanceUntilIdle()
        val modelsRequest = channel.sentEnvelopes.last { it.type == MessageType.ModelsList }
        channel.enqueue(
            envelope(
                type = MessageType.ModelsResult,
                serializer = ModelsResultPayload.serializer(),
                payload = ModelsResultPayload(
                    models = modelPayloads,
                ),
                requestId = modelsRequest.requestId,
            ),
        )
        if (leaveScheduledTimeoutsPending) runCurrent() else advanceUntilIdle()

        return RuntimeClientFixture(
            viewModel = viewModel,
            channel = channel,
            localStore = localStore,
        )
    }

    private fun RuntimeModel.toModelInfoPayload(): ModelInfoPayload {
        return ModelInfoPayload(
            id = id.removePrefix("$provider:"),
            name = name,
            provider = provider,
            modelKind = modelKind,
            capabilities = capabilities,
            qualifiedId = id,
            installed = installed,
            source = source,
            contextWindowTokens = contextWindowTokens,
        )
    }

    private fun ScriptedRuntimeProtocolChannel.lastChatSendPayload(): ChatSendPayload {
        val envelope = sentEnvelopes.last { it.type == MessageType.ChatSend }
        return json.decodeFromJsonElement(ChatSendPayload.serializer(), envelope.payload)
    }

