    private fun testAttachmentOnlyPromptHeader(languageTag: String): String {
        return when (RuntimeAppLanguage.normalizeLanguageTag(languageTag)) {
            RuntimeAppLanguage.Korean.languageTag -> "첨부한 입력을 분석하세요:"
            RuntimeAppLanguage.Japanese.languageTag -> "添付された入力を分析してください:"
            RuntimeAppLanguage.SimplifiedChinese.languageTag -> "请分析附加输入："
            RuntimeAppLanguage.French.languageTag -> "Analysez les éléments joints :"
            else -> "Analyze attached input:"
        }
    }

    private fun signedRuntimeAuthChallenge(
        keyPair: KeyPair,
        nonce: String,
        transportBinding: String?,
        runtimeCapabilities: List<String> = listOf(MEMORY_SUMMARY_DRAFT_APPROVAL_METHOD_CAPABILITY),
    ): ProtocolEnvelope {
        val signature = Signature.getInstance("SHA256withECDSA").run {
            initSign(keyPair.private)
            update(
                com.localagentbridge.android.core.pairing.RuntimeIdentityProofVerifier.authenticationChallengeMessage(
                    deviceId = "client-1",
                    nonce = nonce,
                    transportBinding = transportBinding,
                )
            )
            Base64.getEncoder().encodeToString(sign())
        }
        return envelope(
            type = MessageType.AuthChallenge,
            serializer = com.localagentbridge.android.core.protocol.AuthChallengePayload.serializer(),
            payload = com.localagentbridge.android.core.protocol.AuthChallengePayload(
                deviceId = "client-1",
                nonce = nonce,
                runtimeSignature = signature,
                runtimeCapabilities = runtimeCapabilities,
                transportBinding = transportBinding,
            ),
            requestId = "auth-$nonce",
        )
    }

    @OptIn(ExperimentalCoroutinesApi::class)
    private suspend fun TestScope.completeRuntimeAuthentication(
        viewModel: RuntimeClientViewModel,
        channel: ScriptedRuntimeProtocolChannel,
        requestId: String = "auth-accepted",
        transportBinding: String? = channel.transportSecurityContext?.bindingId,
        runtimeCapabilities: List<String> = listOf(MEMORY_SUMMARY_DRAFT_APPROVAL_METHOD_CAPABILITY),
    ) {
        val trustedBeforeAuthentication = viewModel.state.value.trustedRuntime
        if (trustedBeforeAuthentication != null) {
            viewModel.replaceStateForTest { state ->
                state.copy(
                    trustedRuntime = trustedBeforeAuthentication.copy(
                        fingerprint = initialPairingRuntimeFingerprint,
                        publicKeyBase64 = initialPairingRuntimePublicKey,
                    ),
                )
            }
        }
        val authResponseCount = channel.sentEnvelopes.count { it.type == MessageType.AuthResponse }
        channel.enqueue(
            signedRuntimeAuthChallenge(
                keyPair = initialPairingRuntimeKeyPair,
                nonce = "nonce-$requestId",
                transportBinding = transportBinding,
                runtimeCapabilities = runtimeCapabilities,
            ).copy(requestId = requestId),
        )
        runCurrent()
        assertEquals(
            authResponseCount + 1,
            channel.sentEnvelopes.count { it.type == MessageType.AuthResponse },
        )
        if (trustedBeforeAuthentication != null) {
            viewModel.replaceStateForTest { state ->
                state.copy(trustedRuntime = trustedBeforeAuthentication)
            }
        }
        channel.enqueue(
            envelope(
                type = MessageType.AuthResponse,
                serializer = AuthResponsePayload.serializer(),
                payload = AuthResponsePayload(
                    accepted = true,
                    transportBinding = transportBinding,
                ),
                requestId = requestId,
            ),
        )
        runCurrent()
    }

    private fun verifyAuthenticationSignature(
        publicKeyBase64: String,
        message: ByteArray,
        signatureBase64: String,
    ): Boolean {
        val publicKey = KeyFactory.getInstance("EC").generatePublic(
            X509EncodedKeySpec(Base64.getDecoder().decode(publicKeyBase64))
        )
        return Signature.getInstance("SHA256withECDSA").run {
            initVerify(publicKey)
            update(message)
            verify(Base64.getDecoder().decode(signatureBase64))
        }
    }

    private fun generateAuthenticationKeyPair(): KeyPair {
        return KeyPairGenerator.getInstance("EC")
            .apply { initialize(ECGenParameterSpec("secp256r1")) }
            .generateKeyPair()
    }

